// n8n webhook node configuration
const vexSDK = require('@vex_dev/sdk');

const policyId = 'fintech-n8n-agent'; // Your Vex policy ID
const workflowData = $input.all();
const aiOutput = $json.aiResponse; // From previous AI Agent node

const result = await vexSDK.evaluate({
  policyId,
  context: {
    workflowId: $workflow.id,
    nodeName: $node.name,
    aiOutput,
    userId: $json.userId,
    hasConsent: $json.gdprConsent,
    isProduction: $env.PRODUCTION
  },
  evidence: {
    fullPayload: workflowData,
    executionTrace: $execution
  }
});

if (!result.compliant) {
  throw new Error(`Vex blocked: ${result.reason}`);
}

return [{ json: { vexPassed: true, score: result.score } }];

