// Add to Vex webhook node for recursion protection
const MAX_DEPTH = 5;
const currentDepth = $json.executionDepth || 0;

const recursionCheck = await vexSDK.evaluate({
  policyId: 'n8n-recursion-guard',
  context: {
    workflowId: $workflow.id,
    currentDepth,
    nodeHistory: $json.nodeHistory || [],
    triggerChain: $json.triggerChain
  }
});

if (currentDepth > MAX_DEPTH || !recursionCheck.compliant) {
  return [{ json: { blocked: true, reason: 'Recursion detected' } }];
}

// Pass execution depth to next node
const nextData = { ...$json, executionDepth: currentDepth + 1 };
